<div id="cursor-glow" class="pointer-events-none fixed top-0 left-0 mix-blend-screen" style="z-index: 99999999; pointer-events: none; transform: translate3d(-100px, -100px, 0);">
  <div class="rounded-full transition-smooth animate-pulse" style="width: 280px; height: 280px; background: radial-gradient(circle, oklch(0.68 0.22 250 / 0.35) 0%, transparent 70%); filter: blur(8px); will-change: transform;"></div>
</div>
<div id="cursor-dot" class="pointer-events-none fixed top-0 left-0 rounded-full flex items-center justify-center text-center font-display text-[8px] font-bold uppercase tracking-wider text-black transition-smooth" style="z-index: 100000000; pointer-events: none; width: 10px; height: 10px; background-color: #fff; border: 2.5px solid var(--electric); box-shadow: 0 0 15px var(--electric), 0 0 30px rgba(0, 242, 254, 0.4); transform: translate3d(-100px, -100px, 0); will-change: transform, width, height, background-color;">
  <span id="cursor-label" class="opacity-0 transition-smooth"></span>
</div>
